# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import json
from flask import Flask, request, jsonify
from collections import Counter

app = Flask(__name__)

# In-memory storage for image labels
image_labels = {}

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    
    if image_id not in image_labels:
        image_labels[image_id] = []
    
    image_labels[image_id].append(label)
    
    return jsonify({'status': 'success'}), 200

@app.route('/aggregate/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    if image_id in image_labels:
        votes = image_labels[image_id]
        most_common_label, _ = Counter(votes).most_common(1)[0]
        return jsonify({'label': most_common_label})
    else:
        return jsonify({'error': 'No labels found for this image'}), 404

if __name__ == '__main__':
    app.run(debug=True)